# -*- coding: utf-8 -*-
"""Каталог архитектурных инвариантов v7.6.

Инвариант — это проверка, которую нельзя забывать при проектировании
интеграции. В отличие от частного правила, инвариант формулирует общий
принцип: ключи должны иметь область уникальности, событие должно иметь
конверт, retry должен быть идемпотентным, внешняя зависимость должна иметь
деградацию и т.д.

Каталог намеренно широкий. Он не претендует на математически полный список
всех возможных ошибок в любых системах, но покрывает основные классы
производственных дефектов в интеграциях, API, event-driven потоках,
финансовых/регуляторных процессах, DWH, миграциях и эксплуатации.
"""
from __future__ import annotations
import re


def _s(x):
    return str(x or '').strip()


def _low(x):
    return _s(x).lower()


def _blob(model):
    meta = model.get('meta') or {}
    steps = model.get('steps') or []
    systems = model.get('systems') or {}
    return ' '.join([
        _low(meta.get('name')), _low(meta.get('entity')), _low(meta.get('goal')),
        _low(meta.get('description')), _low(meta.get('lookup_keys')), _low(meta.get('constraints')),
        ' '.join(_low(f.get('name')) + ' ' + _low(f.get('type')) for f in meta.get('fields', [])),
        ' '.join(_low(s.get('name')) + ' ' + _low(s.get('channel')) + ' ' + _low(s.get('data_in')) + ' ' + _low(s.get('data_out')) + ' ' + _low(s.get('compensation')) for s in steps),
        ' '.join(_low(k) + ' ' + _low(v.get('role')) + ' ' + _low(v.get('owner')) for k, v in systems.items()),
    ])


def _probe(status, area, title, question, why, how, examples=None, code=None):
    return {
        'status': status,
        'area': area,
        'title': title,
        'question': question,
        'why': why,
        'how': how,
        'examples': examples or [],
        'code': code or '',
    }


