def _context(model):
    meta = model.get('meta') or {}
    steps = model.get('steps') or []
    systems = model.get('systems') or {}
    graph = model.get('graph') or {}
    channels = {s.get('channel') for s in steps}
    roles = {v.get('role') for v in systems.values()}
    blob = _blob(model)
    has_sensitive = bool(meta.get('regulatory') or any(f.get('sensitive') for f in meta.get('fields', [])) or re.search(r'пдн|паспорт|email|телефон|secret|секрет|personal|sensitive', blob))
    has_db = 'db' in channels or 'db' in roles or any(s.get('writes_entity') for s in steps)
    return {
        'base': True,
        'data': bool(meta.get('fields') or meta.get('lookup_keys') or any(s.get('writes_entity') for s in steps)),
        'writes': any(s.get('writes_entity') for s in steps),
        'events': bool(channels & {'ibm_mq', 'redis_streams', 'rabbitmq', 'gcp_pubsub', 'queue', 'callback', 'activemq', 'websocket', 'redis_queue', 'mqtt', 'webhook', 'sns_sqs', 'sse', 'nats', 'kafka', 'pulsar', 'azure_service_bus'}),
        'kafka': 'kafka' in channels,
        'async': bool(graph.get('async_steps')) or bool(channels & {'callback', 'batch', 'clickhouse', 'lakehouse', 'spark', 'nats', 'cdc', 'redis_streams', 'cassandra', 'gcp_pubsub', 'queue', 'sftp', 'workflow_engine', 'sns_sqs', 'kafka', 'pulsar', 'azure_service_bus', 'ibm_mq', 'data_lake', 'activemq', 'data_warehouse', 'etl', 'airflow', 'rabbitmq', 'sse', 'object_storage', 'dbt', 'file', 'observability', 'websocket', 'redis_queue', 'mqtt', 'webhook', 'bpm_engine'}),
        'sync': any(s.get('blocking') and s.get('channel') in {'search', 'cdn', 'mongodb', 'vector_db', 'grpc', 'service_mesh', 'api_gateway', 'db', 'graphql', 'vault', 'esb', 'dynamodb', 'redis_cache', 'read_replica', 'db_sharding', 'memcached', 'rest', 'auth_oidc', 'odata', 'redis_lock', 'soap'} for s in steps),
        'external': bool(graph.get('external_blocking')) or 'external' in roles,
        'webhook': bool(channels & {'webhook', 'callback', 'websocket', 'sse'}),
        'file_batch': bool(channels & {'file', 'batch', 'sftp', 'etl', 'spark', 'airflow', 'object_storage', 'dbt'}),
        'money': meta.get('money') == 'direct',
        'regulatory': bool(meta.get('regulatory')),
        'sensitive': has_sensitive,
        'highload': int(meta.get('peak_rps') or 0) >= 1000 or int(meta.get('load_rps') or 0) >= 500,
        'customer': bool(meta.get('customer_visible')),
        'multitenant': bool(meta.get('multi_tenant')) or bool(re.search(r'tenant|мультитенант|multi.?tenant', blob)),
        'legacy': bool(meta.get('replacing_legacy')) or 'legacy' in roles or bool(re.search(r'legacy|легаси|миграц|замен', blob)),
        'dwh': 'analytics' in roles or 'cdc' in channels or bool(re.search(r'dwh|витрин|аналит|warehouse|cdc|etl', blob)),
        'read': meta.get('read_freq') in {'high', 'very_high'} or bool(re.search(r'read.?model|projection|кэш|cache|чтени', blob)),
        'db': has_db,
        'migration': bool(meta.get('replacing_legacy')) or bool(re.search(r'migration|миграц|cutover|rollback|legacy|релиз|deploy', blob)),
        'security': True,
        'observability': len({s.get('system') for s in steps}) >= 2 or bool(channels & {'ibm_mq', 'redis_streams', 'rabbitmq', 'gcp_pubsub', 'queue', 'callback', 'activemq', 'websocket', 'redis_queue', 'mqtt', 'webhook', 'sns_sqs', 'sse', 'nats', 'kafka', 'pulsar', 'azure_service_bus'}),
        'operations': True,
    }


def universal_invariant_probes(model, findings=None, patterns=None, completeness=None):
    ctx = _context(model)
    blob = _blob(model)
    fired = {f.get('rule') for f in (findings or [])}
    probes = []

    # Правила ядра, которые должны переводить близкие инварианты в fail.
    fail_hints = {
        'ID-001': {'ambiguous_composite_business_key', 'generic_identifier_scope_ambiguity', 'missing_key_scope_for_shared_dispatcher'},
        'ID-002': {'ambiguous_composite_business_key', 'retry_without_idempotency'},
        'CON-001': {'event_core_fields'},
        'CON-002': {'contract_versioning'},
        'CON-003': {'api_error_contract'},
        'SCN-003': {'status_model'},
        'DAT-001': {'multiple_writers', 'money_controls'},
        'DAT-002': {'dual_write'},
        'DAT-003': {'callback_inbox', 'retry_without_idempotency'},
        'DAT-005': {'saga_without_compensation'},
        'ASY-001': {'async_without_recovery', 'poison_retry'},
        'ASY-004': {'ordering'},
        'API-001': {'missing_timeouts'},
        'API-003': {'external_blocking', 'unstable_dependency'},
        'EXT-004': {'inbound_security'},
        'DWH-001': {'analytics_in_core'},
        'PERF-002': {'stream_consumer_controls', 'stream_ingestion'},
        'OBS-001': {'no_correlation_id', 'observability_missing'},
        'CMP-001': {'regulatory_audit'},
    }

    for inv in INVARIANT_CATALOG:
        if not ctx.get(inv['scope'], False):
            continue
        status = 'ok' if re.search(inv.get('evidence') or r'$', blob) else inv.get('missing_status', 'unknown')
        if inv['scope'] in {'external', 'async', 'kafka', 'webhook', 'money', 'regulatory', 'sensitive', 'highload', 'security'} and status == 'unknown':
            status = 'warn'
        if fired & fail_hints.get(inv['code'], set()):
            status = 'fail'
        probes.append(_probe(status, inv['area'], inv['title'], inv['question'], inv['why'], inv['how'], inv.get('examples'), inv['code']))
    return probes


def invariant_catalog_stats(model):
    ctx = _context(model)
    applicable = sum(1 for inv in INVARIANT_CATALOG if ctx.get(inv['scope'], False))
    return {'total': len(INVARIANT_CATALOG), 'applicable': applicable}
